// Open opens a connection to the db given a configuration.
func Open(cfg config.Config) (*sql.DB, Driver, error) {
	sql, driver, err := open(cfg.Database, false)
	if err != nil {
		return nil, 0, err
	}

	sql.SetMaxIdleConns(cfg.Database.MaxIdleConn)

	if cfg.Database.MaxOpenConn > 0 {
		sql.SetMaxOpenConns(cfg.Database.MaxOpenConn)
	}
	if cfg.Database.ConnMaxLifetime > 0 {
		sql.SetConnMaxLifetime(cfg.Database.ConnMaxLifetime)
	}

	registerMetrics(driver, sql)

	return sql, driver, nil
}

func open(cfg interface{}, migrate bool) (*sql.DB, Driver, error) {
	d, url, err := parse(cfg, migrate)
	if err != nil {
		return nil, 0, err
	}

	driverName := fmt.Sprintf("instrumented-%s", d)

	var dr driver.Driver

	switch d {
	case SQLite:
		dr = &sqlite3.SQLiteDriver{}
	case Postgres:
		dr = &pq.Driver{}
	case MySQL:
		dr = &mysql.MySQLDriver{}
	}

	registered := false

	for _, dd := range sql.Drivers() {
		if dd == driverName {
			registered = true
			break
		}
	}

	if !registered {
		sql.Register(driverName, instrumentedsql.WrapDriver(dr, instrumentedsql.WithTracer(opentracing.NewTracer(false))))
	}

	db, err := sql.Open(driverName, url.DSN)
	if err != nil {
		return nil, 0, fmt.Errorf("opening db for driver: %s %w", d, err)
	}

	return db, d, nil
}

func databaseConfig(cfg interface{}) (config.DatabaseConfig, error) {
	switch c := cfg.(type) {
	case string:
		return config.DatabaseConfig{URL: c}, nil
	case config.Config:
		return c.Database, nil
	case *config.Config:
		if c == nil {
			return config.DatabaseConfig{}, fmt.Errorf("database config cannot be nil")
		}
		return c.Database, nil
	case config.DatabaseConfig:
		return c, nil
	case *config.DatabaseConfig:
		if c == nil {
			return config.DatabaseConfig{}, fmt.Errorf("database config cannot be nil")
		}
		return *c, nil
	default:
		return config.DatabaseConfig{}, fmt.Errorf("unsupported database config: %T", cfg)
	}
}

func databaseURL(cfg interface{}) (string, error) {
	dbCfg, err := databaseConfig(cfg)
	if err != nil {
		return "", err
	}

	return dbCfg.URLString()
}

