// Open opens a connection to the db given a configuration
func Open(cfg config.Config) (*sql.DB, Driver, error) {
	sql, driver, err := open(cfg, false)
	if err != nil {
		return nil, 0, err
	}

	sql.SetMaxIdleConns(cfg.Database.MaxIdleConn)

	if cfg.Database.MaxOpenConn > 0 {
		sql.SetMaxOpenConns(cfg.Database.MaxOpenConn)
	}
	if cfg.Database.ConnMaxLifetime > 0 {
		sql.SetConnMaxLifetime(cfg.Database.ConnMaxLifetime)
	}

	registerMetrics(driver, sql)

	return sql, driver, nil
}

func open(cfg config.Config, migrate bool) (*sql.DB, Driver, error) {
	d, url, err := parse(cfg, migrate)
	if err != nil {
		return nil, 0, err
	}

	driverName := fmt.Sprintf("instrumented-%s", d)

	var dr driver.Driver

	switch d {
	case SQLite:
		dr = &sqlite3.SQLiteDriver{}
	case Postgres:
		dr = &pq.Driver{}
	case MySQL:
		dr = &mysql.MySQLDriver{}
	}

	registered := false

	for _, dd := range sql.Drivers() {
		if dd == driverName {
			registered = true
			break
		}
	}

	if !registered {
		sql.Register(driverName, instrumentedsql.WrapDriver(dr, instrumentedsql.WithTracer(opentracing.NewTracer(false))))
	}

	db, err := sql.Open(driverName, url.DSN)
	if err != nil {
		return nil, 0, fmt.Errorf("opening db for driver: %s %w", d, err)
	}

	return db, d, nil
}

func databaseURL(cfg config.Config) (string, error) {
	dbCfg := cfg.Database

	if strings.TrimSpace(dbCfg.URL) != "" {
		return dbCfg.URL, nil
	}

	if err := dbCfg.Validate(); err != nil {
		return "", err
	}

	name := strings.TrimSpace(dbCfg.Name)

	switch dbCfg.Protocol {
	case config.DatabaseProtocolSQLite:
		return (&url.URL{Scheme: "file", Opaque: name}).String(), nil
	case config.DatabaseProtocolPostgres, config.DatabaseProtocolMySQL:
		host := strings.TrimSpace(dbCfg.Host)
		user := strings.TrimSpace(dbCfg.User)

		if dbCfg.Port != 0 {
			host = fmt.Sprintf("%s:%d", host, dbCfg.Port)
		}

		scheme := dbCfg.Protocol.String()
		u := &url.URL{
			Scheme: scheme,
			Host:   host,
			Path:   "/" + strings.TrimPrefix(name, "/"),
		}

		if user != "" {
			if dbCfg.Password != "" {
				u.User = url.UserPassword(user, dbCfg.Password)
			} else {
				u.User = url.User(user)
			}
		}

		return u.String(), nil
	default:
		return "", fmt.Errorf("unsupported database protocol: %s", dbCfg.Protocol)
	}
}

